from agent import *from models.products import *import simplejsondef run(context: dict[str, str], session: Session):    session.sessionbreakers = [SessionBreak(max_requests=10000)]    session.queue(Request("https://www.loot.co.za/search?offset=0&vprice_min=&vprice_max=&cat=b&terms=", use='curl', max_age=0, force_charset='utf-8'), process_prodlist, dict())def process_prodlist(data: Response, context: dict[str, str], session: Session):    prod_cnt = context.get('prod_cnt')    offset = context.get("offset", 0) + 24    resp = data.xpath('//script[@id="__NEXT_DATA__"]//text()').string()    if resp:        json = simplejson.loads(resp)        prod_cnt = json.get('props', {}).get('pageProps', {}).get('initialState', {}).get('searchResult', {}).get('hits')        if prod_cnt:            prod_cnt = int(prod_cnt)        prods = json.get('props', {}).get('pageProps', {}).get('initialState', {}).get('searchResult', {}).get('products', [])        for prod in prods:            prod_info = prod.get('productInfo')            rating_cnt = int(prod_info.get('ratingCount'))            if rating_cnt and rating_cnt > 0:                url = "https://www.loot.co.za" + prod_info["shareLink"]["uri"]                session.queue(Request(url, use='curl', max_age=0, force_charset='utf-8'), process_product, dict(url=url))    else:        offset -= 23    # Error 502    if offset < int(prod_cnt):        url = "https://www.loot.co.za/search?offset=" + str(offset) + "&vprice_min=&vprice_max=&cat=b&terms="        session.queue(Request(url, use='curl', max_age=0, force_charset='utf-8'), process_prodlist, dict(context, offset=offset, prod_cnt=prod_cnt))def process_product(data: Response, context: dict[str, str], session: Session):    resp = data.xpath("//script[@id='__NEXT_DATA__']//text()").string()    try:        json = simplejson.loads(resp)    except:        return    prod_data = json.get('props', {}).get('pageProps', {}).get('initialProps', {}).get('product', {})    product = Product()    product.name = prod_data.get('productInfo', {}).get("fullTitle")    product.url = context["url"]    product.ssid = prod_data.get('details', {}).get('General', {}).get('ISBN-13')    if not product.ssid:        product.ssid = prod_data.get('productInfo', {}).get("code")    mpn = prod_data.get('details', {}).get('General', {}).get('LSN')    if mpn:        product.add_property(type="id.manufacturer", value=mpn)    ean = prod_data.get('details', {}).get('General', {}).get('Barcode')    if ean:        product.add_property(type="id.ean", value=ean)    product.category = prod_data.get('parent', {}).get('name')    if not product.category:        product.category = 'Tech'    brand = prod_data.get('brand')    if brand:        product.manufacturer = brand.get("label")    revs = prod_data.get('reviews', {}).get('results', [])    for rev in revs:        review = Review()        review.type = "user"        review.url = product.url        review.title = rev.get("title")        review.date = rev.get("createdDate")        author = rev.get("reviewer")        if author:            review.authors.append(Person(name=author, ssid=author))        grade_overall = rev.get('rating')        if grade_overall or grade_overall == 0:            value = float(grade_overall)            review.grades.append(Grade(type="overall", value=value, best=5.0, worst=0.0))        excerpt = rev.get("review")        if excerpt and excerpt != 'no review':            review.add_property(type="excerpt", value=excerpt)            review.ssid = str(rev.get("id"))            if not review.ssid:                review.ssid = review.ssid = review.digest() if author else review.digest(excerpt)            product.reviews.append(review)    if product.reviews:        session.emit(product)